  const parseMaybeJson = (v) => {
    if (typeof v !== "string") return v;
    const s = v.trim();
    if (!s) return v;
    if (s.startsWith("{") || s.startsWith("[")) {
      try { return JSON.parse(s); } catch (e) { return v; }
    }
    return v;
  };

  const body = {
    schema: $json.schema,
    entry_ids: parseMaybeJson($json.entry_ids),
    range: parseMaybeJson($json.range),
    dry_run: $json.dry_run,
    force: $json.force,
  };

  // Type normalization (only if upstream sends strings)
  if (typeof body.dry_run === "string") body.dry_run = (body.dry_run === "true");
  if (typeof body.force === "string") body.force = (body.force === "true");

  return body;
})()) }}

