'use strict';

const { mdv2Message } = require('@igasovic/n8n-blocks/shared/telegram-markdown.js');

const s = $json || {};
  const lines = [
    'Move successful',
    `Dry run: ${String(s.dry_run)}`,
    `Schema: ${String(s.from_schema ?? '')} -> ${String(s.to_schema ?? '')}`,
    `Moved: ${String(s.moved_count ?? 0)}`,
  ];
  return [{ json: { ...$json, telegram_message: mdv2Message(lines.join('\n')) } }];

'use strict';

const { mdv2, bold, bullet, joinLines, finalizeMarkdownV2 } = require('@igasovic/n8n-blocks/shared/telegram-markdown.js');

  const { $json = {} } = ctx || {};
  const status = String($json.status || '').trim().toLowerCase();
  const entryId = String($json.entry_id ?? '-').trim() || '-';

  let telegramMessage = '';

  if (status === 'completed') {
    const summary = mdv2($json.summary || 'n/a');
    const why = mdv2($json.why_it_matters || 'n/a');
    const excerpt = mdv2($json.excerpt || '');
    const stance = mdv2($json.stance || 'n/a');
    const lines = [
      bold('Tier_2 distill completed'),
      bullet(`Entry: ${entryId}`, { rawValue: true }),
      bullet(`Stance: ${stance}`, { rawValue: true }),
      '',
      bold('Summary'),
      summary,
      '',
      bold('Why it matters'),
      why,
    ];
    if (excerpt) {
      lines.push('', bold('Excerpt'), excerpt);
    }
    telegramMessage = finalizeMarkdownV2(joinLines(lines, { trimTrailing: true }));
  } else {
    const errorCode = mdv2($json.error_code || 'unknown_error');
    const message = mdv2($json.message || 'distill failed');
    const preserved = String($json.preserved_current_artifact === true);
    telegramMessage = joinLines([
      bold('Tier_2 distill failed'),
      bullet(`Entry: ${mdv2(entryId)}`, { rawValue: true }),
      bullet(`Error: ${errorCode}`, { rawValue: true }),
      bullet(`Message: ${message}`, { rawValue: true }),
      bullet(`Current artifact preserved: ${mdv2(preserved)}`, { rawValue: true }),
    ], { trimTrailing: true });
    telegramMessage = finalizeMarkdownV2(telegramMessage);
  }

  return [{
    json: {
      ...$json,
      telegram_message: telegramMessage,
    },
  }];

'use strict';

const smokeMode = $json.smoke_mode === true;
  if (!smokeMode) {
    return [{ json: { ...$json } }];
  }

  const assertions = [];
  const cmd = String($json.cmd || '').trim();
  assertions.push({ name: 'command_present', ok: !!cmd, command: cmd || null });
  const msg = String($json.telegram_message || '');
  assertions.push({ name: 'telegram_message_non_empty', ok: msg.length > 0 });
  const telegramMessageId = $json.message_id ?? ($json.result && $json.result.message_id) ?? null;
  if (telegramMessageId != null) assertions.push({ name: 'telegram_message_id_present', ok: true });

  if (cmd === 'pull') {
    assertions.push({ name: 'pull_entry_present', ok: !!($json.entry_id || ($json.rows && $json.rows.length)) });
  }
  if (cmd === 'continue') {
    const count = Number($json.count_hits || $json.rows_count || 0);
    assertions.push({ name: 'continue_rows_available', ok: count >= 0, count });
  }
  if (cmd === 'distill') {
    const status = String($json.status || '').toLowerCase();
    assertions.push({ name: 'distill_status_present', ok: status.length > 0, status });
  }
  if (cmd === 'delete') {
    const deleted = Number($json.deleted_count ?? 0);
    assertions.push({ name: 'delete_response_present', ok: Number.isFinite(deleted), deleted_count: deleted });
  }

  const ok = assertions.every((assertion) => assertion.ok === true);
  return [{
    json: {
      ...$json,
      test_case: 'read_command',
      ok,
      run_id: $json.test_run_id || null,
      artifacts: {
        command: cmd,
        telegram_message: msg || null,
        telegram_message_id: telegramMessageId,
        entry_id: $json.entry_id ?? null,
        deleted_count: $json.deleted_count ?? null,
      },
      assertions,
      error: ok ? null : { message: 'read command assertions failed' },
    },
  }];

'use strict';

const { mdv2, bold, parens, joinLines, finalizeMarkdownV2 } = require('@igasovic/n8n-blocks/shared/telegram-markdown.js');

const r = $json || {};
const mode = String(r.mode || 'run').toLowerCase();
const executionMode = String(r.execution_mode || 'sync').toLowerCase() === 'batch' ? 'batch' : 'sync';
const lines = [];

lines.push(mode === 'dry_run' ? `${bold('Tier_1 classify')} ${parens('dry run')}` : bold('Tier_1 classify'));
lines.push(`${bold('Execution:')} ${mdv2(executionMode)}`);
if (r.batch_id) lines.push(`${bold('Batch_id:')} ${mdv2(r.batch_id)}`);
lines.push('');
lines.push(`${bold('Candidates:')} ${r.candidate_count ?? 0}`);
lines.push(`${bold('Runnable:')} ${r.runnable_count ?? 0}`);
if (Number(r.skipped_missing_clean_text || 0) > 0) lines.push(`Skipped missing clean text: ${Number(r.skipped_missing_clean_text || 0)}`);

if (mode === 'dry_run') {
  lines.push(`${bold('Would process:')} ${r.will_process_count ?? r.runnable_count ?? 0}`);
} else if (executionMode === 'batch') {
  lines.push(`${bold('Enqueued:')} ${r.enqueued_count ?? r.request_count ?? 0}`);
  if (r.status) lines.push(`Batch status: ${mdv2(r.status)}`);
} else {
  lines.push(`${bold('Processed:')} ${r.processed_count ?? 0}`);
  lines.push(`Completed: ${r.completed_count ?? 0}`);
  lines.push(`Failed: ${r.failed_count ?? 0}`);
  const topFailures = Object.entries((r && r.error_code_counts) || {})
    .sort((a, b) => Number(b[1] || 0) - Number(a[1] || 0))
    .slice(0, 3);
  if (topFailures.length) lines.push(`Top failures: ${topFailures.map(([code, count]) => `${mdv2(code)} ${parens(Number(count || 0))}`).join(', ')}`);
}

return [{ json: { ...r, telegram_message: finalizeMarkdownV2(joinLines(lines, { trimTrailing: true })) } }];
